import{_ as e,o as i,c as l,ai as n}from"./chunks/framework.DKRJm8HN.js";const u=JSON.parse('{"title":"公开学习","description":"","frontmatter":{"title":"公开学习","date":"2026-03-24"},"headers":[],"relativePath":"docs/B-Journal/learning-in-public.md","filePath":"docs/B-Journal/learning-in-public.md"}'),t={name:"docs/B-Journal/learning-in-public.md"};function r(o,a,p,c,s,_){return i(),l("div",null,[...a[0]||(a[0]=[n('<h1 id="公开学习" tabindex="-1">公开学习 <a class="header-anchor" href="#公开学习" aria-label="Permalink to “公开学习”">​</a></h1><p>最近开始尝试公开学习，把学习过程和思考记录下来分享。</p><p>为什么要公开学习？</p><ul><li>写作能帮助整理思路</li><li>分享能获得反馈和建议</li><li>记录能追踪学习进度</li><li>公开承诺更有动力坚持</li></ul><p>刚开始可能会觉得不好意思，怕写错被人笑话。但后来想通了：每个人都是从不懂到懂的过程，展示这个过程没什么丢人的。</p><p>而且，你认为很简单的东西，可能对别人很有价值。你踩过的坑，别人可能也会踩到。</p><p>现在我在博客上记录学习笔记，技术心得，还有生活感悟。不追求完美，只追求真实和有用。</p><p>持续输出，持续进步。</p>',8)])])}const m=e(t,[["render",r]]);export{u as __pageData,m as default};
